package com.treeeducation.ioas.lead; import io.swagger.v3.oas.annotations.media.Schema;import jakarta.validation.constraints.*; /** Lead DTOs. */ public final class LeadDtos{private LeadDtos(){} @Schema(description="创建线索请求") public record CreateRequest(@NotNull Long packageId,@NotNull Long assetFileId,Long operatorId,@NotBlank String customerName,String phone,String remark){} @Schema(description="更新线索状态请求") public record StatusRequest(@NotNull LeadStatus status){} @Schema(description="线索响应") public record Response(Long id,Long packageId,Long assetFileId,Long operatorId,String customerName,String phone,String remark,LeadStatus status){} public static Response of(Lead l){return new Response(l.getId(),l.getPackageId(),l.getAssetFileId(),l.getOperatorId(),l.getCustomerName(),l.getPhone(),l.getRemark(),l.getStatus());}}
